// ─────────────────────────────────────────────────────────────────────────────
// Config
// ─────────────────────────────────────────────────────────────────────────────

/// Structural configuration for a Pneuma TTS acoustic model.
///
/// Defaults track Piper small (`hidden_dim=192`, 6 layers, 2 heads); a base
/// VITS-class config can be obtained by overriding `hidden_dim` to 384 and
/// scaling `encoder_intermediate_size` accordingly.
#[derive(Debug, Clone, PartialEq)]
pub struct TtsConfig {
    /// Number of phoneme symbols in the vocabulary (~256 for eSpeak).
    pub vocab_size: usize,
    /// Hidden dimension of the encoder (`d_model`). 192 for Piper small.
    pub hidden_dim: usize,
    /// Number of transformer blocks in the phoneme encoder.
    pub encoder_layers: usize,
    /// Attention heads per encoder block.
    pub encoder_heads: usize,
    /// MLP intermediate size — typically `4 * hidden_dim`.
    pub encoder_intermediate_size: usize,
    /// Number of mel filterbank channels in the output spectrogram. 80.
    pub n_mels: usize,
    /// Number of speakers — 1 for the single-speaker v1 model.
    pub n_speakers: usize,
    /// LayerNorm epsilon.
    pub eps: f32,
}

impl Default for TtsConfig {
    /// Defaults to Piper small (single-speaker, 192-dim, 6-layer encoder).
    fn default() -> Self {
        Self {
            vocab_size: 256,
            hidden_dim: 192,
            encoder_layers: 6,
            encoder_heads: 2,
            encoder_intermediate_size: 768, // 4 * 192
            n_mels: 80,
            n_speakers: 1,
            eps: 1e-5,
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// parse_tts_config
// ─────────────────────────────────────────────────────────────────────────────

/// Read a value from a JSON object under any of the supplied key aliases.
/// Tolerates HF/Piper snake_case and an alternate camelCase emitted by some
/// conversion pipelines — same pattern as [`crate::loader_whisper`].
fn pick<'a>(obj: &'a Value, keys: &[&str]) -> Option<&'a Value> {
    for k in keys {
        if let Some(v) = obj.get(k) {
            if !v.is_null() {
                return Some(v);
            }
        }
    }
    None
}

fn as_usize(v: &Value) -> Option<usize> {
    v.as_u64().map(|n| n as usize)
}

/// Parse a [`TtsConfig`] from a `.knot` metadata blob.
///
/// Looks for a top-level `config` object (or treats `meta` as the config
/// itself if no wrapper is present). Missing fields fall back to Piper-small
/// defaults so a sparsely-encoded knot still produces a usable config —
/// downstream tensor-shape validation catches genuine mismatches.
pub fn parse_tts_config(meta: &Value) -> Result<TtsConfig, String> {
    let cfg = meta.get("config").unwrap_or(meta);
    if !cfg.is_object() {
        return Err("parse_tts_config: `config` is not a JSON object".to_string());
    }

    let d = TtsConfig::default();

    let hidden_dim = pick(cfg, &["hidden_dim", "hiddenDim", "d_model", "dModel"])
        .and_then(as_usize)
        .unwrap_or(d.hidden_dim);

    let encoder_intermediate_size = pick(
        cfg,
        &[
            "encoder_intermediate_size",
            "encoderIntermediateSize",
            "encoder_ffn_dim",
            "encoderFfnDim",
            "intermediate_size",
            "intermediateSize",
        ],
    )
    .and_then(as_usize)
    .unwrap_or(4 * hidden_dim);

    Ok(TtsConfig {
        vocab_size: pick(cfg, &["vocab_size", "vocabSize", "n_vocab", "nVocab"])
            .and_then(as_usize)
            .unwrap_or(d.vocab_size),
        hidden_dim,
        encoder_layers: pick(
            cfg,
            &["encoder_layers", "encoderLayers", "n_layer", "nLayer"],
        )
        .and_then(as_usize)
        .unwrap_or(d.encoder_layers),
        encoder_heads: pick(
            cfg,
            &[
                "encoder_heads",
                "encoderHeads",
                "encoder_attention_heads",
                "encoderAttentionHeads",
                "n_head",
                "nHead",
            ],
        )
        .and_then(as_usize)
        .unwrap_or(d.encoder_heads),
        encoder_intermediate_size,
        n_mels: pick(cfg, &["n_mels", "nMels", "num_mels", "numMels"])
            .and_then(as_usize)
            .unwrap_or(d.n_mels),
        n_speakers: pick(
            cfg,
            &["n_speakers", "nSpeakers", "num_speakers", "numSpeakers"],
        )
        .and_then(as_usize)
        .unwrap_or(d.n_speakers),
        eps: pick(cfg, &["eps", "layer_norm_eps", "layerNormEps"])
            .and_then(|v| v.as_f64())
            .map(|n| n as f32)
            .unwrap_or(d.eps),
    })
}

// ─────────────────────────────────────────────────────────────────────────────
// KnotCodec — TTS-acoustic-local codec marker
// ─────────────────────────────────────────────────────────────────────────────

// Payload codec carried by a `.knot` file.
//
// Mirrors the file-level codec marker the encoder writes between the header
// metadata and the tensor payload (`0x10` fp16, `0x20` fp32; see
// `open-source/bitwise/scripts/encode-piper-knot.ts`). The TTS acoustic loader
// needs to know this so it can dequantize fp16 tensors to f32 before feeding
// them to the kernels. Scoped to TTS acoustic for now: Whisper paths in
// `model_whisper_*.rs`.
// ─────────────────────────────────────────────────────────────────────────────
// Tensor name composition
// ─────────────────────────────────────────────────────────────────────────────

/// Compose a `.knot` tensor name for a Pneuma TTS acoustic model weight.
///
/// Mirrors [`crate::loader_whisper::whisper_tensor_name`] but for the
/// `tts_` namespace:
///
/// - `tts_tensor_name(Some(0), "attn_q.weight")` -> `"tts_blk_0_attn_q.weight"`
/// - `tts_tensor_name(None, "phoneme_embed.weight")` -> `"tts_phoneme_embed.weight"`
pub fn tts_tensor_name(layer: Option<usize>, role: &str) -> String {
    match layer {
        Some(i) => format!("tts_blk_{}_{}", i, role),
        None => format!("tts_{}", role),
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Cached tensor name addresses
// ─────────────────────────────────────────────────────────────────────────────

/// Cached tensor names for one TTS encoder block. Resolving the format string
/// once per block (instead of per forward pass) keeps the hot path free of
/// allocations — same pattern Whisper uses.
#[derive(Debug, Clone)]
struct TtsBlockNames {
    ln1_w: String,
    ln1_b: String,
    attn_q_w: String,
    attn_q_b: String,
    attn_k_w: String,
    // K projection has no bias (matches the Whisper / Piper convention).
    attn_v_w: String,
    attn_v_b: String,
    attn_out_w: String,
    attn_out_b: String,
    ln2_w: String,
    ln2_b: String,
    mlp_fc1_w: String,
    mlp_fc1_b: String,
    mlp_fc2_w: String,
    mlp_fc2_b: String,
}

impl TtsBlockNames {
    fn new(layer: usize) -> Self {
        let l = Some(layer);
        Self {
            ln1_w: tts_tensor_name(l, "ln1.weight"),
            ln1_b: tts_tensor_name(l, "ln1.bias"),
            attn_q_w: tts_tensor_name(l, "attn_q.weight"),
            attn_q_b: tts_tensor_name(l, "attn_q.bias"),
            attn_k_w: tts_tensor_name(l, "attn_k.weight"),
            attn_v_w: tts_tensor_name(l, "attn_v.weight"),
            attn_v_b: tts_tensor_name(l, "attn_v.bias"),
            attn_out_w: tts_tensor_name(l, "attn_out.weight"),
            attn_out_b: tts_tensor_name(l, "attn_out.bias"),
            ln2_w: tts_tensor_name(l, "ln2.weight"),
            ln2_b: tts_tensor_name(l, "ln2.bias"),
            mlp_fc1_w: tts_tensor_name(l, "mlp_fc1.weight"),
            mlp_fc1_b: tts_tensor_name(l, "mlp_fc1.bias"),
            mlp_fc2_w: tts_tensor_name(l, "mlp_fc2.weight"),
            mlp_fc2_b: tts_tensor_name(l, "mlp_fc2.bias"),
        }
    }
}

/// Cached tensor names for one WaveNet (WN) layer within a flow block.
#[derive(Debug, Clone)]
struct TtsWnLayerNames {
    in_w: String,
    in_b: String,
    res_w: String,
    res_b: String,
}

impl TtsWnLayerNames {
    fn new(flow_idx: usize, layer_idx: usize) -> Self {
        Self {
            in_w: format!("tts_flow_blk_{}_wn_layer_{}_in.weight", flow_idx, layer_idx),
            in_b: format!("tts_flow_blk_{}_wn_layer_{}_in.bias", flow_idx, layer_idx),
            res_w: format!(
                "tts_flow_blk_{}_wn_layer_{}_res.weight",
                flow_idx, layer_idx
            ),
            res_b: format!("tts_flow_blk_{}_wn_layer_{}_res.bias", flow_idx, layer_idx),
        }
    }
}

/// Cached tensor names for one Normalising Flow block.
#[derive(Debug, Clone)]
struct TtsFlowBlockNames {
    pre_w: String,
    pre_b: String,
    post_w: String,
    post_b: String,
    wn_layers: Vec<TtsWnLayerNames>,
}

impl TtsFlowBlockNames {
    fn new(idx: usize, wn_layers: usize) -> Self {
        let wn = (0..wn_layers)
            .map(|l| TtsWnLayerNames::new(idx, l))
            .collect();
        Self {
            pre_w: format!("tts_flow_blk_{}_pre.weight", idx),
            pre_b: format!("tts_flow_blk_{}_pre.bias", idx),
            post_w: format!("tts_flow_blk_{}_post.weight", idx),
            post_b: format!("tts_flow_blk_{}_post.bias", idx),
            wn_layers: wn,
        }
    }
}

#[derive(Debug, Clone)]
struct TtsDurNames {
    pre_w: String,
    pre_b: String,
    proj_w: String,
    proj_b: String,
    conv_sep_w: Vec<String>,
    conv_sep_b: Vec<String>,
    conv_1x1_w: Vec<String>,
    conv_1x1_b: Vec<String>,
}

impl TtsDurNames {
    fn new(num_layers: usize) -> Self {
        let mut sep_w: Vec<String> = Vec::with_capacity(num_layers);
        let mut sep_b: Vec<String> = Vec::with_capacity(num_layers);
        let mut p_1x1_w: Vec<String> = Vec::with_capacity(num_layers);
        let mut p_1x1_b: Vec<String> = Vec::with_capacity(num_layers);

        for i in 0..num_layers {
            sep_w.push(format!("tts_dp_convs_convs_sep_{}_weight", i));
            sep_b.push(format!("tts_dp_convs_convs_sep_{}_bias", i));
            p_1x1_w.push(format!("tts_dp_convs_convs_1x1_{}_weight", i));
            p_1x1_b.push(format!("tts_dp_convs_convs_1x1_{}_bias", i));
        }

        Self {
            pre_w: "tts_dur_predictor_fc1.weight".to_string(),
            pre_b: "tts_dur_predictor_fc1.bias".to_string(),
            proj_w: "tts_dur_predictor_fc2.weight".to_string(),
            proj_b: "tts_dur_predictor_fc2.bias".to_string(),
            conv_sep_w: sep_w,
            conv_sep_b: sep_b,
            conv_1x1_w: p_1x1_w,
            conv_1x1_b: p_1x1_b,
        }
    }
}

/// Cached top-level tensor names (embedding + mel projection).
#[derive(Debug, Clone)]
struct TtsTopNames {
    phoneme_embed: String,
    mel_proj_w: String,
    mel_proj_b: String,
    dur: TtsDurNames,
}

impl TtsTopNames {
    fn new() -> Self {
        Self {
            phoneme_embed: tts_tensor_name(None, "phoneme_embed.weight"),
            mel_proj_w: tts_tensor_name(None, "mel_proj.weight"),
            mel_proj_b: tts_tensor_name(None, "mel_proj.bias"),
            dur: TtsDurNames::new(3),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// TtsAcousticModel
// ─────────────────────────────────────────────────────────────────────────────

/// Pneuma TTS acoustic model: phoneme IDs -> mel-spectrogram.
///
/// Construction is cheap; weight bytes are fetched lazily per `forward()` via
/// the `backend`. Per-utterance scratch buffers are sized at `new()` from a
/// conservative `max_phonemes` cap (default 1024) and reused across calls.
/// The output mel buffer is allocated per call because its length depends on
/// the input length × predicted durations.
pub struct TtsAcousticModel {
    /// Encoder dims + mel/speaker counts.
    config: TtsConfig,
    /// Weight source (mmap, HTTP, or wasm-host backend).
    backend: Arc<dyn WeightBackend>,
    /// Payload codec — controls how raw tensor bytes are interpreted on read.
    /// fp16 (2 B/elt) is dequantized to f32 inline; fp32 (4 B/elt) is
    /// borrowed through with no copy.
    codec: KnotCodec,
    /// Exact resident memo for repeated F32 projections.
    memo: matvec_memo::MatVecMemo,
    /// Per-block tensor name cache.
    blocks: Vec<TtsBlockNames>,
    /// Top-level tensor name cache.
    top: TtsTopNames,
    /// Per-flow tensor name cache.
    flows: Vec<TtsFlowBlockNames>,
    /// Maximum supported phoneme sequence length (sizes the scratch buffers).
    max_phonemes: usize,

    // ── Scratch buffers (allocated once, reused per forward) ────────────
    /// Working hidden state (seq, hidden), seq <= max_phonemes.
    x: Vec<f32>,
    /// Per-token LN/residual scratch (seq, hidden).
    xb: Vec<f32>,
    /// Per-token attention output scratch (seq, hidden).
    attn_out: Vec<f32>,
    /// Per-token Q projections (seq, hidden).
    q_buf: Vec<f32>,
    /// Per-token K projections (seq, hidden).
    k_buf: Vec<f32>,
    /// Per-token V projections (seq, hidden).
    v_buf: Vec<f32>,
    /// MLP intermediate (seq, intermediate_size).
    mlp_buf: Vec<f32>,

    // ── Flow scratch buffers ────────────────────────────────────────────
    /// Flow working buffer (hidden, seq_frames).
    flow_x: Vec<f32>,
    /// Flow scratch (hidden, seq_frames).
    flow_scratch: Vec<f32>,
    /// WN accumulate skip (hidden, seq_frames).
    wn_skip: Vec<f32>,
}

impl TtsAcousticModel {
    /// Construct an acoustic model from a parsed config and a weight backend.
    /// Pre-resolves all tensor names and allocates scratch buffers sized for
    /// the default maximum sequence length (1024 phonemes ≈ 47 s of speech at
    /// the v1 stub's 4 frames/phoneme).
    ///
    /// Defaults the payload codec to fp32 — pre-existing call-sites that
    /// don't yet thread the `.knot` codec marker through retain their
    /// original behaviour. Use [`TtsAcousticModel::with_codec`] for fp16
    /// knots; loading an fp16 knot through this constructor will panic at
    /// the first tensor fetch with `phoneme_embed too small: N < 2N`.
    pub fn new(config: TtsConfig, backend: Arc<dyn WeightBackend>) -> Self {
        Self::with_codec_and_max_phonemes(config, backend, KnotCodec::Fp32, 4096)
    }

    /// Construct with an explicit payload codec. Required for fp16 `.knot`
    /// files, which halve disk size at the cost of an inline dequantize on
    /// every tensor fetch. Read the codec from the `.knot` metadata's
    /// top-level `"codec"` field via [`parse_tts_codec`].
    pub fn with_codec(
        config: TtsConfig,
        backend: Arc<dyn WeightBackend>,
        codec: KnotCodec,
    ) -> Self {
        Self::with_codec_and_max_phonemes(config, backend, codec, 4096)
    }

    /// Construct with an explicit `max_phonemes` cap. Use when the caller
    /// knows phoneme inputs will exceed the default 1024-symbol bound.
    /// Defaults codec to fp32 — see [`TtsAcousticModel::new`].
    pub fn with_max_phonemes(
        config: TtsConfig,
        backend: Arc<dyn WeightBackend>,
        max_phonemes: usize,
    ) -> Self {
        Self::with_codec_and_max_phonemes(config, backend, KnotCodec::Fp32, max_phonemes)
    }

    /// Full constructor: explicit codec and max-phonemes cap.
    pub fn with_codec_and_max_phonemes(
        config: TtsConfig,
        backend: Arc<dyn WeightBackend>,
        codec: KnotCodec,
        max_phonemes: usize,
    ) -> Self {
        let hidden = config.hidden_dim;
        let inter = config.encoder_intermediate_size;
        let seq = max_phonemes;
        let flow_seq = seq * 64; // Conservative max frames

        let blocks = (0..config.encoder_layers).map(TtsBlockNames::new).collect();
        let top = TtsTopNames::new();
        // Piper medium: 4 flows (0, 2, 4, 6), each with a 4-layer WN.
        let flows = (0..4).map(|i| TtsFlowBlockNames::new(i * 2, 4)).collect();

        Self {
            blocks,
            top,
            flows,
            max_phonemes,
            x: vec![0.0; seq * hidden],
            xb: vec![0.0; seq * hidden],
            attn_out: vec![0.0; seq * hidden],
            q_buf: vec![0.0; seq * hidden],
            k_buf: vec![0.0; seq * hidden],
            v_buf: vec![0.0; seq * hidden],
            mlp_buf: vec![0.0; seq * inter],
            flow_x: vec![0.0; flow_seq * hidden],
            flow_scratch: vec![0.0; flow_seq * hidden * 2], // WN hidden is usually 2x
            wn_skip: vec![0.0; flow_seq * hidden],
            config,
            backend,
            codec,
            memo: {
                let mut memo = matvec_memo::MatVecMemo::new();
                memo.set_enabled(true);
                memo.set_tau_squared(0.0);
                memo
            },
        }
    }

    /// Borrow the configured payload codec.
    pub fn codec(&self) -> KnotCodec {
        self.codec
    }

    /// Enable/disable exact F32 projection memoization.
    pub fn memo_enable(&mut self, enabled: bool) {
        self.memo.set_enabled(enabled);
    }

    /// Clear resident projection memo state.
    pub fn memo_clear(&mut self) {
        self.memo.clear();
    }

    /// `(hits, misses, evictions)` for resident projection memo state.
    pub fn memo_stats(&self) -> (u64, u64, u64) {
        self.memo.stats()
    }

    // ── Normalising Flow Implementation ──────────────────────────────────

    fn apply_flow(&mut self, z: &mut [f32], frames: usize) {
        // z: (hidden, frames)
        for i in 0..self.flows.len() {
            let flow_names = self.flows[i].clone();
            self.apply_residual_coupling_layer(z, &flow_names, frames);
            self.flip_channels(z, frames);
        }
    }

    fn flip_channels(&self, z: &mut [f32], frames: usize) {
        let hidden = self.config.hidden_dim;
        for t in 0..frames {
            for c in 0..hidden / 2 {
                let c1 = c;
                let c2 = hidden - 1 - c;
                let v1 = z[c1 * frames + t];
                let v2 = z[c2 * frames + t];
                z[c1 * frames + t] = v2;
                z[c2 * frames + t] = v1;
            }
        }
    }

    fn apply_residual_coupling_layer(
        &mut self,
        z: &mut [f32],
        names: &TtsFlowBlockNames,
        frames: usize,
    ) {
        let hidden = self.config.hidden_dim;
        let half = hidden / 2;

        let mut x_in = vec![0.0f32; half * frames];
        x_in.copy_from_slice(&z[..half * frames]);

        self.apply_wavenet(&x_in, names, frames);

        // Stats (m) is in self.flow_scratch (96 channels).
        // Piper flows in lessac-medium seem to be additive: z1 = z1 - m
        for t in 0..frames {
            for c in 0..half {
                let m = self.flow_scratch[c * frames + t];
                let z1_idx = (half + c) * frames + t;
                z[z1_idx] -= m;
            }
        }
    }

    fn apply_wavenet(&mut self, x: &[f32], names: &TtsFlowBlockNames, frames: usize) {
        let half = self.config.hidden_dim / 2; // 96
        let hidden = self.config.hidden_dim; // 192
        let codec = self.codec;

        // pre_conv: 1x1 conv on x(96) -> flow_x(192)
        let pre_w_bytes = self.backend.fetch_tensor(&names.pre_w).unwrap();
        let pre_b_bytes = self.backend.fetch_tensor(&names.pre_b).unwrap();
        let pre_w = bytes_to_f32_slice_codec(&pre_w_bytes, codec);
        let pre_b = bytes_to_f32_slice_codec(&pre_b_bytes, codec);

        for v in self.flow_x[..hidden * frames].iter_mut() {
            *v = 0.0;
        }
        crate::math_pneuma::conv1d(
            &mut self.flow_x[..hidden * frames],
            x,
            &pre_w,
            Some(&pre_b),
            half,
            hidden,
            frames,
            1,
            1,
            0,
        );

        // Clear wn_skip (Stats sum: 192 channels)
        for v in self.wn_skip[..hidden * frames].iter_mut() {
            *v = 0.0;
        }

        for (i, layer) in names.wn_layers.iter().enumerate() {
            let dilation = 2usize.pow(i as u32);
            let pad = (3 - 1) * dilation / 2; // kernel=3

            let in_w_bytes = self.backend.fetch_tensor(&layer.in_w).unwrap();
            let in_b_bytes = self.backend.fetch_tensor(&layer.in_b).unwrap();
            let in_w = bytes_to_f32_slice_codec(&in_w_bytes, codec);
            let in_b = bytes_to_f32_slice_codec(&in_b_bytes, codec);

            // output of in_layers has 2 * hidden channels (384). Use flow_scratch.
            let gated = &mut self.flow_scratch[..hidden * 2 * frames];
            crate::math_pneuma::conv1d_dilated(
                gated,
                &self.flow_x[..hidden * frames],
                &in_w,
                Some(&in_b),
                hidden,
                hidden * 2,
                frames,
                3,
                1,
                pad,
                dilation,
            );

            // Gated activation: tanh(a) * sigmoid(b). Reduces 384 -> 192.
            for t in 0..frames {
                for c in 0..hidden {
                    let a = gated[c * frames + t];
                    let b = gated[(hidden + c) * frames + t];
                    gated[c * frames + t] = a.tanh() * (1.0 / (1.0 + (-b).exp()));
                }
            }

            let res_w_bytes = self.backend.fetch_tensor(&layer.res_w).unwrap();
            let res_b_bytes = self.backend.fetch_tensor(&layer.res_b).unwrap();
            let res_w = bytes_to_f32_slice_codec(&res_w_bytes, codec);
            let res_b = bytes_to_f32_slice_codec(&res_b_bytes, codec);

            // res_skip output: hidden * 2 (384) for normal layers, hidden (192) for the last layer.
            let out_ch = if i == names.wn_layers.len() - 1 {
                hidden
            } else {
                hidden * 2
            };
            let mut res_skip_out = vec![0.0f32; out_ch * frames];
            crate::math_pneuma::conv1d(
                &mut res_skip_out,
                &gated[..hidden * frames],
                &res_w,
                Some(&res_b),
                hidden,
                out_ch,
                frames,
                1,
                1,
                0,
            );

            // Accumulate skip into wn_skip. Add residual back to flow_x.
            for t in 0..frames {
                for c in 0..hidden {
                    if i < names.wn_layers.len() - 1 {
                        let res_val = res_skip_out[c * frames + t];
                        let skip_val = res_skip_out[(hidden + c) * frames + t];
                        self.flow_x[c * frames + t] += res_val;
                        self.wn_skip[c * frames + t] += skip_val;
                    } else {
                        // Last layer only has skip connection.
                        let skip_val = res_skip_out[c * frames + t];
                        self.wn_skip[c * frames + t] += skip_val;
                    }
                }
            }
        }

        let post_w_bytes = self.backend.fetch_tensor(&names.post_w).unwrap();
        let post_b_bytes = self.backend.fetch_tensor(&names.post_b).unwrap();
        let post_w = bytes_to_f32_slice_codec(&post_w_bytes, codec);
        let post_b = bytes_to_f32_slice_codec(&post_b_bytes, codec);

        // Final stats into flow_scratch (m: 96 channels)
        crate::math_pneuma::conv1d(
            &mut self.flow_scratch[..half * frames],
            &self.wn_skip[..hidden * frames],
            &post_w,
            Some(&post_b),
            hidden,
            half,
            frames,
            1,
            1,
            0,
        );
    }

    /// Predict per-phoneme durations using the stochastic duration predictor.
    /// Currently implements the "mean" path (mu) for inference stability.
    fn predict_durations(&self, x: &[f32], seq: usize) -> Vec<usize> {
        let hidden = self.config.hidden_dim;
        let codec = self.codec;
        let names = &self.top.dur;

        // 1. dp.pre: (hidden, seq) -> (hidden, seq)
        let mut h = vec![0.0f32; hidden * seq];
        {
            let w_bytes = self.backend.fetch_tensor(&names.pre_w).unwrap();
            let b_bytes = self.backend.fetch_tensor(&names.pre_b).unwrap();
            let w = bytes_to_f32_slice_codec(&w_bytes, codec);
            let b = bytes_to_f32_slice_codec(&b_bytes, codec);
            // x is (seq, hidden), we need (hidden, seq) for conv
            let mut x_transposed = vec![0.0f32; hidden * seq];
            for t in 0..seq {
                for c in 0..hidden {
                    x_transposed[c * seq + t] = x[t * hidden + c];
                }
            }
            crate::math_pneuma::conv1d(
                &mut h,
                &x_transposed,
                &w,
                Some(&b),
                hidden,
                hidden,
                seq,
                1,
                1,
                0,
            );
        }

        // 2. dp.convs: residual blocks
        for i in 0..names.conv_sep_w.len() {
            let mut dw_out = vec![0.0f32; hidden * seq];
            {
                let dw_w_bytes = self.backend.fetch_tensor(&names.conv_sep_w[i]).unwrap();
                let dw_b_bytes = self.backend.fetch_tensor(&names.conv_sep_b[i]).unwrap();
                let pw_w_bytes = self.backend.fetch_tensor(&names.conv_1x1_w[i]).unwrap();
                let pw_b_bytes = self.backend.fetch_tensor(&names.conv_1x1_b[i]).unwrap();

                let dw_w = bytes_to_f32_slice_codec(&dw_w_bytes, codec);
                let dw_b = bytes_to_f32_slice_codec(&dw_b_bytes, codec);
                let pw_w = bytes_to_f32_slice_codec(&pw_w_bytes, codec);
                let pw_b = bytes_to_f32_slice_codec(&pw_b_bytes, codec);

                crate::math_pneuma::conv1d_depthwise_separable(
                    &mut dw_out,
                    &h,
                    &dw_w,
                    &pw_w,
                    Some(&dw_b),
                    Some(&pw_b),
                    hidden,
                    seq,
                    3,
                    1,
                    1,
                );
            }
            // Residual add
            for j in 0..h.len() {
                h[j] += dw_out[j];
            }
        }

        // 3. dp.proj: (hidden, seq) -> (2, seq)
        let mut stats = vec![0.0f32; 2 * seq];
        {
            let w_bytes = self.backend.fetch_tensor(&names.proj_w).unwrap();
            let b_bytes = self.backend.fetch_tensor(&names.proj_b).unwrap();
            let w = bytes_to_f32_slice_codec(&w_bytes, codec);
            let b = bytes_to_f32_slice_codec(&b_bytes, codec);
            crate::math_pneuma::conv1d(&mut stats, &h, &w, Some(&b), hidden, 2, seq, 1, 1, 0);
        }

        // 4. Sample durations (using mu)
        let mut durations = Vec::with_capacity(seq);
        for t in 0..seq {
            let log_dur = stats[t]; // mu is the first channel
            let dur = log_dur.exp().round().max(1.0) as usize;
            durations.push(dur);
        }
        durations
    }

    /// Borrow the model's parsed configuration.
    pub fn config(&self) -> &TtsConfig {
        &self.config
    }

    /// Run the acoustic model forward.
    ///
    /// `phonemes`: phoneme IDs from the G2P front-end (each `< vocab_size`).
    /// Returns: row-major `(n_mels, n_frames)` mel-spectrogram, where
    /// `n_frames` is the sum of per-phoneme durations from the duration predictor.
    ///
    /// Panics if `phonemes.len() == 0` or exceeds `max_phonemes`, or if any
    /// phoneme ID is out of vocab range.
    pub fn forward(&mut self, phonemes: &[u32]) -> Vec<f32> {
        let cfg = &self.config;
        let hidden = cfg.hidden_dim;
        let inter = cfg.encoder_intermediate_size;
        let n_mels = cfg.n_mels;
        let eps = cfg.eps;
        let seq = phonemes.len();

        assert!(
            seq > 0,
            "TtsAcousticModel.forward: phoneme sequence is empty"
        );
        assert!(
            seq <= self.max_phonemes,
            "TtsAcousticModel.forward: phoneme length {} exceeds max_phonemes {}",
            seq,
            self.max_phonemes,
        );

        // ── 1. Phoneme embedding -> x[0..seq*hidden] ────────────────────
        {
            let embed = self.backend.fetch_tensor(&self.top.phoneme_embed).unwrap();
            let embed_cow = bytes_to_f32_slice_codec(&embed, self.codec);
            let embed_f: &[f32] = &embed_cow;
            assert!(
                embed_f.len() >= cfg.vocab_size * hidden,
                "phoneme_embed tensor too small: {} < {}",
                embed_f.len(),
                cfg.vocab_size * hidden,
            );
            for (t, &pid) in phonemes.iter().enumerate() {
                let pid = pid as usize;
                assert!(
                    pid < cfg.vocab_size,
                    "phoneme id {} >= vocab_size {}",
                    pid,
                    cfg.vocab_size,
                );
                let src = &embed_f[pid * hidden..(pid + 1) * hidden];
                let dst = &mut self.x[t * hidden..(t + 1) * hidden];
                dst.copy_from_slice(src);
            }
        }

        // ── 2. Add sinusoidal positional embedding (computed inline) ────
        // No tensor — the standard transformer sin/cos positional encoding,
        // matching Vaswani et al. 2017. Avoiding a tensor here means the
        // `.knot` doesn't have to ship a max-length pos table.
        for t in 0..seq {
            let row = &mut self.x[t * hidden..(t + 1) * hidden];
            add_sinusoidal_positional(row, t, hidden);
        }

        // ── 3. Encoder blocks ────────────────────────────────────────────
        for l in 0..cfg.encoder_layers {
            self.encoder_block(l, hidden, inter, seq, eps);
        }

        // ── 4. Duration predictor ────────────────────────────────────────
        let durations = self.predict_durations(&self.x[..seq * hidden], seq);
        let n_frames: usize = durations.iter().sum();

        // ── 5. Length regulator ──────────────────────────────────────────
        // Expand each phoneme's hidden vector by its predicted duration.
        // Result: (n_frames, hidden) row-major in `expanded`.
        let mut expanded = vec![0.0f32; n_frames * hidden];
        let mut frame_cursor = 0usize;
        for (t, &dur) in durations.iter().enumerate() {
            let src = &self.x[t * hidden..(t + 1) * hidden];
            for _ in 0..dur {
                let dst_off = frame_cursor * hidden;
                expanded[dst_off..dst_off + hidden].copy_from_slice(src);
                frame_cursor += 1;
            }
        }
        debug_assert_eq!(frame_cursor, n_frames);

        // ── 6. Normalising flow decoder ──────────────────────────────────
        // Transpose: (n_frames, hidden) -> (hidden, n_frames)
        // hidden_seq is (hidden, n_frames).
        let mut hidden_seq = vec![0.0f32; hidden * n_frames];
        for f in 0..n_frames {
            for c in 0..hidden {
                hidden_seq[c * n_frames + f] = expanded[f * hidden + c];
            }
        }

        self.apply_flow(&mut hidden_seq, n_frames);

        // Transpose back: (hidden, n_frames) -> (n_frames, hidden)
        for f in 0..n_frames {
            for c in 0..hidden {
                expanded[f * hidden + c] = hidden_seq[c * n_frames + f];
            }
        }

        // ── 7. Mel projection: linear (n_mels, hidden) per frame ─────────
        // Output layout: row-major (n_mels, n_frames) — what the vocoder
        // (Channel β) consumes. We compute it column-by-column: for each
        // frame produce a length-`n_mels` vector, then scatter into the
        // transposed output.
        let mel_w = self.backend.fetch_tensor(&self.top.mel_proj_w).unwrap();
        let mel_b = self.backend.fetch_tensor(&self.top.mel_proj_b).unwrap();
        let mel_w_cow = bytes_to_f32_slice_codec(&mel_w, self.codec);
        let mel_b_cow = bytes_to_f32_slice_codec(&mel_b, self.codec);
        let mel_w_f: &[f32] = &mel_w_cow;
        let mel_b_f: &[f32] = &mel_b_cow;

        let mut mel = vec![0.0f32; n_mels * n_frames];
        let mut frame_buf = vec![0.0f32; n_mels];
        for f in 0..n_frames {
            matvec_memo::cached_mat_vec_f32(
                &mut self.memo,
                &mut frame_buf,
                &expanded[f * hidden..(f + 1) * hidden],
                mel_w_f,
                n_mels,
                hidden,
                1,
                n_mels,
                self.config.encoder_layers,
                matvec_memo::OP_OUTPUT_PROJ,
                tts_mat_vec_f32_dispatch,
            );
            for m in 0..n_mels {
                mel[m * n_frames + f] = frame_buf[m] + mel_b_f[m];
            }
        }
        mel
    }

    /// One encoder block: pre-LN self-attention + residual, pre-LN MLP +
    /// residual. Operates over the active prefix `seq` of `self.x`.
    fn encoder_block(&mut self, l: usize, hidden: usize, inter: usize, seq: usize, eps: f32) {
        let names = self.blocks[l].clone();
        let num_heads = self.config.encoder_heads;
        debug_assert_eq!(hidden % num_heads, 0, "hidden must divide num_heads");
        let head_dim = hidden / num_heads;
        let scale = 1.0 / (head_dim as f32).sqrt();

        // ── Pre-attention LayerNorm: xb = ln1(x) ─────────────────────────
        {
            let ln1_w = self.backend.fetch_tensor(&names.ln1_w).unwrap();
            let ln1_b = self.backend.fetch_tensor(&names.ln1_b).unwrap();
            let ln1_w_cow = bytes_to_f32_slice_codec(&ln1_w, self.codec);
            let ln1_b_cow = bytes_to_f32_slice_codec(&ln1_b, self.codec);
            let w: &[f32] = &ln1_w_cow;
            let b: &[f32] = &ln1_b_cow;
            for t in 0..seq {
                let off = t * hidden;
                let (src, dst) = (&self.x[off..off + hidden], &mut self.xb[off..off + hidden]);
                layer_norm(dst, src, w, b, eps);
            }
        }

        // ── Q, K, V projections ──────────────────────────────────────────
        // Q has bias.
        {
            let q_w = self.backend.fetch_tensor(&names.attn_q_w).unwrap();
            let q_b = self.backend.fetch_tensor(&names.attn_q_b).unwrap();
            let q_w_cow = bytes_to_f32_slice_codec(&q_w, self.codec);
            let q_b_cow = bytes_to_f32_slice_codec(&q_b, self.codec);
            let q_w_f: &[f32] = &q_w_cow;
            let q_b_f: &[f32] = &q_b_cow;
            for t in 0..seq {
                let off = t * hidden;
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.q_buf[off..off + hidden],
                    &self.xb[off..off + hidden],
                    q_w_f,
                    hidden,
                    hidden,
                    1,
                    hidden,
                    l,
                    matvec_memo::OP_Q,
                    tts_mat_vec_f32_dispatch,
                );
                for h in 0..hidden {
                    self.q_buf[off + h] += q_b_f[h];
                }
            }
        }
        // K has no bias.
        {
            let k_w = self.backend.fetch_tensor(&names.attn_k_w).unwrap();
            let k_w_cow = bytes_to_f32_slice_codec(&k_w, self.codec);
            let k_w_f: &[f32] = &k_w_cow;
            for t in 0..seq {
                let off = t * hidden;
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.k_buf[off..off + hidden],
                    &self.xb[off..off + hidden],
                    k_w_f,
                    hidden,
                    hidden,
                    1,
                    hidden,
                    l,
                    matvec_memo::OP_K,
                    tts_mat_vec_f32_dispatch,
                );
            }
        }
        // V has bias.
        {
            let v_w = self.backend.fetch_tensor(&names.attn_v_w).unwrap();
            let v_b = self.backend.fetch_tensor(&names.attn_v_b).unwrap();
            let v_w_cow = bytes_to_f32_slice_codec(&v_w, self.codec);
            let v_b_cow = bytes_to_f32_slice_codec(&v_b, self.codec);
            let v_w_f: &[f32] = &v_w_cow;
            let v_b_f: &[f32] = &v_b_cow;
            for t in 0..seq {
                let off = t * hidden;
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.v_buf[off..off + hidden],
                    &self.xb[off..off + hidden],
                    v_w_f,
                    hidden,
                    hidden,
                    1,
                    hidden,
                    l,
                    matvec_memo::OP_V,
                    tts_mat_vec_f32_dispatch,
                );
                for h in 0..hidden {
                    self.v_buf[off + h] += v_b_f[h];
                }
            }
        }

        // ── Multi-head self-attention (no causal mask) ───────────────────
        // Bidirectional attention: phoneme encoders see the full context, the
        // same as Whisper's audio encoder. Q,K,V are packed per token as
        // (num_heads, head_dim) within the `hidden`-wide row.
        let q = &self.q_buf;
        let k = &self.k_buf;
        let v = &self.v_buf;
        let attn_dst = &mut self.attn_out;
        for slot in attn_dst[..seq * hidden].iter_mut() {
            *slot = 0.0;
        }
        let mut scores = vec![0.0f32; seq];
        for t in 0..seq {
            for h in 0..num_heads {
                let q_off = t * hidden + h * head_dim;
                let q_head = &q[q_off..q_off + head_dim];

                for s in 0..seq {
                    let k_off = s * hidden + h * head_dim;
                    let mut acc = 0.0f32;
                    for d in 0..head_dim {
                        acc += q_head[d] * k[k_off + d];
                    }
                    scores[s] = acc * scale;
                }
                softmax(&mut scores);

                let out_off = t * hidden + h * head_dim;
                let head_out = &mut attn_dst[out_off..out_off + head_dim];
                for s in 0..seq {
                    let w = scores[s];
                    let v_off = s * hidden + h * head_dim;
                    for d in 0..head_dim {
                        head_out[d] += w * v[v_off + d];
                    }
                }
            }
        }

        // ── Output projection + bias, residual into x ────────────────────
        {
            let o_w = self.backend.fetch_tensor(&names.attn_out_w).unwrap();
            let o_b = self.backend.fetch_tensor(&names.attn_out_b).unwrap();
            let o_w_cow = bytes_to_f32_slice_codec(&o_w, self.codec);
            let o_b_cow = bytes_to_f32_slice_codec(&o_b, self.codec);
            let o_w_f: &[f32] = &o_w_cow;
            let o_b_f: &[f32] = &o_b_cow;
            for t in 0..seq {
                let off = t * hidden;
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.xb[off..off + hidden],
                    &self.attn_out[off..off + hidden],
                    o_w_f,
                    hidden,
                    hidden,
                    1,
                    hidden,
                    l,
                    matvec_memo::OP_O,
                    tts_mat_vec_f32_dispatch,
                );
                for h in 0..hidden {
                    self.x[off + h] += self.xb[off + h] + o_b_f[h];
                }
            }
        }

        // ── Pre-MLP LayerNorm: xb = ln2(x) ───────────────────────────────
        {
            let ln2_w = self.backend.fetch_tensor(&names.ln2_w).unwrap();
            let ln2_b = self.backend.fetch_tensor(&names.ln2_b).unwrap();
            let ln2_w_cow = bytes_to_f32_slice_codec(&ln2_w, self.codec);
            let ln2_b_cow = bytes_to_f32_slice_codec(&ln2_b, self.codec);
            let w: &[f32] = &ln2_w_cow;
            let b: &[f32] = &ln2_b_cow;
            for t in 0..seq {
                let off = t * hidden;
                let (src, dst) = (&self.x[off..off + hidden], &mut self.xb[off..off + hidden]);
                layer_norm(dst, src, w, b, eps);
            }
        }

        // ── MLP: fc1 (+ bias) -> GELU -> fc2 (+ bias) -> residual ────────
        {
            let fc1_w = self.backend.fetch_tensor(&names.mlp_fc1_w).unwrap();
            let fc1_b = self.backend.fetch_tensor(&names.mlp_fc1_b).unwrap();
            let fc1_w_cow = bytes_to_f32_slice_codec(&fc1_w, self.codec);
            let fc1_b_cow = bytes_to_f32_slice_codec(&fc1_b, self.codec);
            let fc1_w_f: &[f32] = &fc1_w_cow;
            let fc1_b_f: &[f32] = &fc1_b_cow;
            for t in 0..seq {
                let in_off = t * hidden;
                let out_off = t * inter;
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.mlp_buf[out_off..out_off + inter],
                    &self.xb[in_off..in_off + hidden],
                    fc1_w_f,
                    inter,
                    hidden,
                    1,
                    inter,
                    l,
                    matvec_memo::OP_FFN_UP,
                    tts_mat_vec_f32_dispatch,
                );
                for h in 0..inter {
                    self.mlp_buf[out_off + h] += fc1_b_f[h];
                }
            }
        }
        gelu_inplace(&mut self.mlp_buf[..seq * inter]);
        {
            let fc2_w = self.backend.fetch_tensor(&names.mlp_fc2_w).unwrap();
            let fc2_b = self.backend.fetch_tensor(&names.mlp_fc2_b).unwrap();
            let fc2_w_cow = bytes_to_f32_slice_codec(&fc2_w, self.codec);
            let fc2_b_cow = bytes_to_f32_slice_codec(&fc2_b, self.codec);
            let fc2_w_f: &[f32] = &fc2_w_cow;
            let fc2_b_f: &[f32] = &fc2_b_cow;
            for t in 0..seq {
                let in_off = t * inter;
                let out_off = t * hidden;
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.xb[out_off..out_off + hidden],
                    &self.mlp_buf[in_off..in_off + inter],
                    fc2_w_f,
                    hidden,
                    inter,
                    1,
                    hidden,
                    l,
                    matvec_memo::OP_FFN_DOWN,
                    tts_mat_vec_f32_dispatch,
                );
                for h in 0..hidden {
                    self.x[out_off + h] += self.xb[out_off + h] + fc2_b_f[h];
                }
            }
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────

fn tts_mat_vec_f32_dispatch(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
) {
    for b in 0..n_batch {
        mat_vec_f32(
            &mut out[b * out_stride..b * out_stride + rows],
            &x[b * cols..b * cols + cols],
            w,
            rows,
            cols,
        );
    }
}

/// Add a Vaswani-style sinusoidal positional encoding to an in-place row.
///
/// `row.len()` must equal `hidden`. Even indices receive sin, odd indices cos,
/// at frequencies `1 / 10000^(2i / hidden)` — the standard transformer scheme.
/// Computed inline (not from a tensor) so the `.knot` doesn't need to ship a
/// max-length positional table.
fn add_sinusoidal_positional(row: &mut [f32], pos: usize, hidden: usize) {
    debug_assert_eq!(row.len(), hidden);
    let pos_f = pos as f32;
    for i in 0..hidden {
        let pair = (i / 2) as f32;
        let inv_freq = (-(2.0 * pair / hidden as f32) * 10000f32.ln()).exp();
        let angle = pos_f * inv_freq;
        if i % 2 == 0 {
            row[i] += angle.sin();
        } else {
            row[i] += angle.cos();
        }
    }
}

/// View raw little-endian f32 bytes returned by [`WeightBackend::fetch_tensor`]
/// as an f32 slice without copying. Caller asserts the payload is f32.
///
/// Pre-fp16 codepath; superseded in the hot path by [`bytes_to_f32_slice_codec`]
/// (which routes via the file-level codec marker). Kept as a thin private
/// helper to preserve a one-call f32 fast path for tests / future call-sites.
#[inline(always)]
#[allow(dead_code)]
fn bytes_to_f32_slice(bytes: &[u8]) -> &[f32] {
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}

/// Codec-aware view onto raw tensor bytes returned by [`WeightBackend::fetch_tensor`].
///
/// - `KnotCodec::Fp32` — zero-copy `&[f32]` borrow of the underlying bytes.
/// - `KnotCodec::Fp16` — owned `Vec<f32>` produced by dequantizing the
///   little-endian fp16 payload via [`crate::math::f16_to_f32`]. The cost is
///   one allocation + one pass per fetch; for the Piper-small acoustic model
///   the largest tensor (mel projection, 80×192 ≈ 60 KB fp16) dequantizes in
///   well under a millisecond on commodity CPUs.
///
/// This helper closes gap #8 from `docs/pneuma/gap-closure-plan.md`: the
/// pre-fix loader treated every tensor as f32, so fp16 `.knot` files panicked
/// at the first read with `phoneme_embed too small: N < 2N` (off by 2x since
/// fp16 is half the bytes). Scoped to TTS only — Whisper paths in
/// `model_whisper_*.rs` carry their own helper and have only been exercised
/// against fp32 knots so far.
#[inline]
fn bytes_to_f32_slice_codec(bytes: &[u8], codec: KnotCodec) -> Cow<'_, [f32]> {
    match codec {
        KnotCodec::Fp32 => {
            // Safety: the encoder writes little-endian f32 payload; bytes
            // are 4-byte aligned in the underlying mmap (knot payload starts
            // at `aligned(10+metaLen)+1` — see loader.rs comments). On the
            // small chance the host architecture is big-endian we'd need a
            // byteswap pass; gnosis targets x86_64 / aarch64 so we don't.
            let slice = unsafe {
                std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4)
            };
            Cow::Borrowed(slice)
        }
        KnotCodec::Fp16 => {
            let n = bytes.len() / 2;
            let mut out = Vec::with_capacity(n);
            // Iterate over u16 little-endian pairs and dequantize each.
            for i in 0..n {
                let lo = bytes[2 * i];
                let hi = bytes[2 * i + 1];
                let h = u16::from_le_bytes([lo, hi]);
                out.push(f16_to_f32(h));
            }
            Cow::Owned(out)
        }
    }
}

