#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    #[test]
    fn default_config_is_piper_small() {
        let c = TtsConfig::default();
        assert_eq!(c.vocab_size, 256);
        assert_eq!(c.hidden_dim, 192);
        assert_eq!(c.encoder_layers, 6);
        assert_eq!(c.encoder_heads, 2);
        assert_eq!(c.encoder_intermediate_size, 4 * 192);
        assert_eq!(c.n_mels, 80);
        assert_eq!(c.n_speakers, 1);
        assert!((c.eps - 1e-5).abs() < 1e-12);
    }

    #[test]
    fn parses_vits_base_from_snake_case() {
        let meta = json!({
            "config": {
                "vocab_size": 178,
                "hidden_dim": 384,
                "encoder_layers": 6,
                "encoder_heads": 2,
                "encoder_intermediate_size": 1536,
                "n_mels": 80,
                "n_speakers": 1,
                "layer_norm_eps": 1e-5
            }
        });
        let c = parse_tts_config(&meta).expect("parse ok");
        assert_eq!(c.vocab_size, 178);
        assert_eq!(c.hidden_dim, 384);
        assert_eq!(c.encoder_layers, 6);
        assert_eq!(c.encoder_intermediate_size, 1536);
    }

    #[test]
    fn parses_camelcase_keys_too() {
        let meta = json!({
            "config": {
                "vocabSize": 256,
                "hiddenDim": 192,
                "encoderLayers": 4,
                "encoderHeads": 2,
            }
        });
        let c = parse_tts_config(&meta).expect("parse ok");
        assert_eq!(c.vocab_size, 256);
        assert_eq!(c.hidden_dim, 192);
        assert_eq!(c.encoder_layers, 4);
        // Default fill-in derives intermediate from hidden.
        assert_eq!(c.encoder_intermediate_size, 4 * 192);
    }

    #[test]
    fn tensor_name_composition() {
        assert_eq!(
            tts_tensor_name(Some(0), "attn_q.weight"),
            "tts_blk_0_attn_q.weight"
        );
        assert_eq!(
            tts_tensor_name(Some(5), "mlp_fc2.bias"),
            "tts_blk_5_mlp_fc2.bias"
        );
        assert_eq!(
            tts_tensor_name(None, "phoneme_embed.weight"),
            "tts_phoneme_embed.weight"
        );
        assert_eq!(tts_tensor_name(None, "mel_proj.bias"), "tts_mel_proj.bias");
    }

    #[test]
    fn sinusoidal_positional_at_pos_zero_is_alternating_zeros_and_ones() {
        // sin(0) = 0, cos(0) = 1.
        let mut row = vec![0.0f32; 8];
        add_sinusoidal_positional(&mut row, 0, 8);
        for i in 0..8 {
            if i % 2 == 0 {
                assert!(row[i].abs() < 1e-6, "even idx {} should be sin(0)=0", i);
            } else {
                assert!(
                    (row[i] - 1.0).abs() < 1e-6,
                    "odd idx {} should be cos(0)=1",
                    i
                );
            }
        }
    }

    // ── KnotCodec / fp16 dequant tests (gap #8 fix) ────────────────────────

    #[test]
    fn parse_tts_codec_defaults_to_fp32_when_absent() {
        let meta = json!({ "config": { "hidden_dim": 192 } });
        assert_eq!(parse_tts_codec(&meta), KnotCodec::Fp32);
    }

    #[test]
    fn parse_tts_codec_recognises_fp16_string() {
        let meta = json!({ "codec": "fp16", "config": {} });
        assert_eq!(parse_tts_codec(&meta), KnotCodec::Fp16);
    }

    #[test]
    fn parse_tts_codec_recognises_fp32_string() {
        let meta = json!({ "codec": "fp32", "config": {} });
        assert_eq!(parse_tts_codec(&meta), KnotCodec::Fp32);
    }

    #[test]
    fn knot_codec_bytes_per_element() {
        assert_eq!(KnotCodec::Fp16.bytes_per_element(), 2);
        assert_eq!(KnotCodec::Fp32.bytes_per_element(), 4);
    }

    #[test]
    fn bytes_to_f32_slice_codec_fp32_returns_borrowed_unchanged() {
        // Four IEEE-754 single-precision floats: 1.0, -2.0, 0.5, -0.0.
        let floats: [f32; 4] = [1.0, -2.0, 0.5, -0.0];
        // Re-encode as little-endian byte payload (matches encoder output).
        let mut bytes = Vec::with_capacity(16);
        for f in &floats {
            bytes.extend_from_slice(&f.to_le_bytes());
        }
        let cow = bytes_to_f32_slice_codec(&bytes, KnotCodec::Fp32);
        assert!(
            matches!(cow, Cow::Borrowed(_)),
            "fp32 path should not allocate"
        );
        assert_eq!(cow.len(), 4);
        for (a, b) in cow.iter().zip(floats.iter()) {
            assert_eq!(
                a.to_bits(),
                b.to_bits(),
                "fp32 round-trip must be bit-exact"
            );
        }
    }

    #[test]
    fn bytes_to_f32_slice_codec_fp16_dequants_known_values() {
        // 4 fp16 little-endian values whose f32 expansion we know exactly:
        //   0x3C00 → +1.0       (sign 0, exp 15, mantissa 0)
        //   0xC000 → -2.0       (sign 1, exp 16, mantissa 0)
        //   0x0000 → +0.0
        //   0x3800 → +0.5       (sign 0, exp 14, mantissa 0)
        //
        // Source: IEEE-754 binary16 reference table (Wikipedia, Half-precision).
        // The fp16 → f32 path is gnosis::math::f16_to_f32, validated against
        // llama.cpp's K-quant scale field decoder.
        let halves: [u16; 4] = [0x3C00, 0xC000, 0x0000, 0x3800];
        let mut bytes = Vec::with_capacity(8);
        for h in &halves {
            bytes.extend_from_slice(&h.to_le_bytes());
        }
        assert_eq!(bytes.len(), 8, "4 fp16 values = 8 bytes");

        let cow = bytes_to_f32_slice_codec(&bytes, KnotCodec::Fp16);
        assert!(
            matches!(cow, Cow::Owned(_)),
            "fp16 path must produce an owned Vec"
        );
        assert_eq!(cow.len(), 4, "8 bytes / 2 B-per-elt = 4 floats");

        let expected: [f32; 4] = [1.0, -2.0, 0.0, 0.5];
        for (i, (got, want)) in cow.iter().zip(expected.iter()).enumerate() {
            assert!(
                (got - want).abs() < 1e-12,
                "fp16 dequant idx {}: got {}, want {}",
                i,
                got,
                want,
            );
        }
    }

    #[test]
    fn bytes_to_f32_slice_codec_fp16_payload_is_half_the_size() {
        // Same 4 logical floats encoded as fp16 (8 B) and fp32 (16 B) — the
        // off-by-2x factor is exactly what gap #8 was failing to account for.
        let halves: [u16; 4] = [0x3C00, 0xC000, 0x3800, 0x4000];
        let mut fp16_bytes = Vec::with_capacity(8);
        for h in &halves {
            fp16_bytes.extend_from_slice(&h.to_le_bytes());
        }

        let floats: [f32; 4] = [1.0, -2.0, 0.5, 2.0];
        let mut fp32_bytes = Vec::with_capacity(16);
        for f in &floats {
            fp32_bytes.extend_from_slice(&f.to_le_bytes());
        }

        assert_eq!(
            fp16_bytes.len() * 2,
            fp32_bytes.len(),
            "fp32 payload is 2x the byte size of fp16 — the original bug"
        );

        let fp16 = bytes_to_f32_slice_codec(&fp16_bytes, KnotCodec::Fp16);
        let fp32 = bytes_to_f32_slice_codec(&fp32_bytes, KnotCodec::Fp32);
        assert_eq!(
            fp16.len(),
            fp32.len(),
            "after dequant both views should expose the same logical element count"
        );
    }
}
